const { chromium } = require\('playwright'\);
\(async \(\) => {
  const browser = await chromium.launch\(\);
  const page = await browser.newPage\(\);
  await page.setViewportSize\({ width: 1280, height: 800 }\);
  await page.goto\('http://localhost:5177'\);
  await page.waitForTimeout\(1500\);

  const info = await page.evaluate\(\(\) => {
    const footer = document.querySelector\('footer'\);
    // Check if mt-auto CSS is actually being generated
    const sheets = Array.from\(document.styleSheets\);
    let mtAutoFound = false;
    for \(const sheet of sheets\) {
      try {
        const rules = Array.from\(sheet.cssRules || []\);
        for \(const rule of rules\) {
          if \(rule.cssText && rule.cssText.includes\('mt-auto'\)\) {
            mtAutoFound = rule.cssText;
          }
        }
      } catch\(e\) {}
    }
    // Also check computed flex-related styles of main
    const main = document.querySelector\('main'\);
    const ms = getComputedStyle\(main\);
    return {
      mtAutoFoundInCSS: mtAutoFound,
      footerComputedMarginTop: getComputedStyle\(footer\).marginTop,
      mainHeight: ms.height,
      mainMinHeight: ms.minHeight,
      mainAlignItems: ms.alignItems,
    };
  }\);

  console.log\(JSON.stringify\(info, null, 2\)\);
  await browser.close\(\);
}\)\(\);
